mapper.select:
SELECT id, biz_type, model_name, user_input, prompt, response_text, final_result, success, error_message, cost_ms, need_review, gmt_create FROM ai_call_log WHERE 1 = 1
AND biz_type = #{bizType}
AND success = #{success}
AND need_review = #{needReview}
ORDER BY gmt_create DESC LIMIT #{limit}
